input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {"name": "logs-shared", "emptyDir": {}}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {"name": "log4j2-config", "configMap": {"name": "es-log4j2", "items": [{"key": "log4j2.properties", "path": "log4j2.properties"}]}}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {"name": "metricbeat-config", "configMap": {"name": "metricbeat-config", "items": [{"key": "metricbeat.yml", "path": "metricbeat.yml"}]}}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {"name": "filebeat-config", "configMap": {"name": "filebeat-config", "items": [{"key": "filebeat.yml", "path": "filebeat.yml"}]}}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {"mountPath": "/usr/share/elasticsearch/logs-shared", "name": "logs-shared"}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {"mountPath": "/usr/share/elasticsearch/config/log4j2.properties", "name": "log4j2-config", "subPath": "log4j2.properties"}
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/-",
    "value": {
      "name": "metricbeat",
      "image": "docker.elastic.co/beats/metricbeat:7.17.9",
      "args": ["-c", "/etc/metricbeat.yml", "-e", "--strict.perms=false"],
      "resources": {
        "limits": {"cpu": "200m", "memory": "256Mi"},
        "requests": {"cpu": "100m", "memory": "128Mi"}
      },
      "volumeMounts": [
        {"mountPath": "/etc/metricbeat.yml", "name": "metricbeat-config", "subPath": "metricbeat.yml", "readOnly": true},
        {"mountPath": "/etc/es-certs", "name": "http-certs", "readOnly": true}
      ]
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/-",
    "value": {
      "name": "filebeat",
      "image": "docker.elastic.co/beats/filebeat:7.17.9",
      "args": ["-c", "/etc/filebeat.yml", "-e", "--strict.perms=false"],
      "resources": {
        "limits": {"cpu": "200m", "memory": "256Mi"},
        "requests": {"cpu": "100m", "memory": "128Mi"}
      },
      "volumeMounts": [
        {"mountPath": "/etc/filebeat.yml", "name": "filebeat-config", "subPath": "filebeat.yml", "readOnly": true},
        {"mountPath": "/usr/share/elasticsearch/logs-shared", "name": "logs-shared", "readOnly": true}
      ]
    }
  }
]' 2>&1

